// Calculated field examples in Tableau

// FIXED — customer's first order date, ignores view filters
{ FIXED [Customer ID] : MIN([Order Date]) }

// INCLUDE — average order value per customer, within the region in view
{ INCLUDE [Customer ID] : AVG([Sales]) }

// EXCLUDE — region's share of total (removes Sub-Category from grain)
[Sales] / { EXCLUDE [Sub-Category] : SUM([Sales]) }

// Context filter pattern: drag [Region] to Context
// before using FIXED to scope the subquery to filtered rows only

// Tableau Extensions API — enforce hierarchy filter on dashboard load
tableau.extensions.initializeAsync().then(() => {
  const dash = tableau.extensions.dashboardContent.dashboard;
  const kpiSheet = dash.worksheets.find(w => w.name === "KPI Overview");
  const detailSheet = dash.worksheets.find(w => w.name === "Detail Table");

  // Collapse detail on init; user drills via Filter Action
  detailSheet.applyFilterAsync("Segment", [], tableau.FilterUpdateType.Replace);

  // Seed KPI sheet with current-quarter range
  kpiSheet.applyRangeFilterAsync("Order Date", {
    min: new Date(new Date().getFullYear(), Math.floor(new Date().getMonth() / 3) * 3, 1),
    max: new Date(),
    nullOption: tableau.NullOption.NonNullValues
  }, tableau.FilterUpdateType.Replace);
});

// Tableau Embedding API v3 — programmatic filter + parameter control
const viz = document.getElementById('tableauViz');

// Replace active filter on a sheet
await viz.applyFilterAsync(
  'Sub-Category',
  ['Chairs', 'Tables'],
  tableau.FilterUpdateType.Replace
);

// Change a named parameter value
const param = await viz.workbook.findParameterAsync('Selected Metric');
await param.changeValueAsync('Profit');

// Trigger a specific dashboard action by name
await viz.workbook.executeCustomSQLAsync('DrillDown_Action');

import { TableauViz, TableauEventType } from '@tableau/embedding-api';
import jwt from 'jsonwebtoken';

// Server-side: generate Connected Apps JWT
function getTableauToken(clientId: string, secretId: string, secret: string, username: string) {
  return jwt.sign(
    { sub: username, scp: ['tableau:views:embed'] },
    secret,
    { algorithm: 'HS256', issuer: clientId, keyid: secretId, expiresIn: '5m' }
  );
}

// Client-side: mount whitelabeled viz
const viz = new TableauViz();
viz.src = 'https://tableau.company.com/views/SalesDashboard/Overview';
viz.token = await fetch('/api/tableau-token').then(r => r.text());
viz.toolbar = 'hidden';
viz.hideTabs = true;
document.getElementById('embed-root')!.appendChild(viz);
viz.addEventListener(TableauEventType.FirstInteractive, () => console.log('ready'));

// cube.js schema — metrics defined once, consumed by Tableau via Postgres SQL API
cube(`Orders`, {
  sql: `SELECT * FROM orders`,
  measures: {
    revenue: {
      sql: `amount`,
      type: `sum`,
      filters: [{ sql: `${CUBE}.status = 'completed'` }],
    },
    avg_order_value: {
      sql: `${revenue} / NULLIF(${count}, 0)`,
      type: `number`,
      format: `currency`,
    },
  },
  dimensions: {
    created_at: { sql: `created_at`, type: `time` },
    region:     { sql: `region`,     type: `string` },
  },
});
